console.log('Test 3: Escaped quotes');
{
  const csv = `name,quote
John,"He said ""Hello"""
Jane,"She replied ""Goodbye"""`;

  const result = parseCSV(csv);
  assert(result.rows.length === 2, 'Should have 2 rows');
  assertEqual(result.rows[0].quote, 'He said "Hello"', 'Should convert "" to single "');
  assertEqual(result.rows[1].quote, 'She replied "Goodbye"', 'Should handle multiple escaped quotes');
  assert(result.errors.length === 0, 'Should have no errors');
  console.log('вң“ Passed');
}

// Test 4: Custom delimiter
console.log('Test 4: Custom delimiter');
{
  const csv = `name|age|city
John|30|NYC
Jane|25|LA`;

  const result = parseCSV(csv, { delimiter: '|' });
  assert(result.headers.length === 3, 'Should have 3 headers');
  assertEqual(result.headers, ['name', 'age', 'city'], 'Headers should match with pipe delimiter');
  assert(result.rows.length === 2, 'Should have 2 rows');
  assertEqual(result.rows[0], { name: 'John', age: 30, city: 'NYC' }, 'Should parse with pipe delimiter');
  assert(result.errors.length === 0, 'Should have no errors');
  console.log('вң“ Passed');
}

// Test 5: Custom quote character
console.log('Test 5: Custom quote character');
{
  const csv = `name,address,age
John,'123 Main St, Apt 5',30
Jane,'456 Oak Ave, Suite 100',25`;

  const result = parseCSV(csv, { quoteChar: "'" });
  assert(result.rows.length === 2, 'Should have 2 rows');
  assertEqual(result.rows[0].address, '123 Main St, Apt 5', 'Should respect custom quote character');
  assert(result.errors.length === 0, 'Should have no errors');
  console.log('вң“ Passed');
}

