{
  const csv = `name,age,city\rJohn,30,NYC\rJane,25,LA`;

  const result = parseCSV(csv, { lineSeparator: '\r' });
  assert(result.rows.length === 2, 'Should have 2 rows with custom line separator');
  assertEqual(result.rows[0], { name: 'John', age: 30, city: 'NYC' }, 'Should parse with custom line separator');
  assert(result.errors.length === 0, 'Should have no errors');
