console.log('Test 11: Type coercion - strings');
{
  const csv = `name,city,notes
John,NYC,Hello world
Jane,LA,Test123
Bob,Chicago,abc-def`;

  const result = parseCSV(csv);
  assert(typeof result.rows[0].city === 'string', 'City should be a string');
  assert(result.rows[0].city === 'NYC', 'City should be "NYC"');
  assert(typeof result.rows[1].notes === 'string', 'Notes should be a string');
  assert(result.rows[1].notes === 'Test123', 'Notes should be "Test123"');
  console.log('вң“ Passed');
}

// Test 12: Malformed row - wrong column count
console.log('Test 12: Malformed row - wrong column count');
{
  const csv = `name,age,city
John,30,NYC
Jane,25
Bob,35,Chicago,Extra`;

  const result = parseCSV(csv);
  assert(result.rows.length === 1, 'Should only have 1 valid row');
  assertEqual(result.rows[0], { name: 'John', age: 30, city: 'NYC' }, 'First row should be valid');
  assert(result.errors.length === 2, 'Should have 2 errors');
  assert(result.errors[0].row === 3, 'First error should be on row 3');
  assert(result.errors[1].row === 4, 'Second error should be on row 4');
  console.log('вң“ Passed');
}

// Test 13: Malformed row - unclosed quote
console.log('Test 13: Malformed row - unclosed quote');
{
  const csv = `name,address,age
John,"123 Main St,30
Jane,"456 Oak Ave",25`;

  const result = parseCSV(csv);
  assert(result.rows.length === 1, 'Should only have 1 valid row');
  assertEqual(result.rows[0], { name: 'Jane', address: '456 Oak Ave', age: 25 }, 'Second row should be valid');
  assert(result.errors.length === 1, 'Should have 1 error');
  assert(result.errors[0].row === 2, 'Error should be on row 2');
  assert(result.errors[0].message === 'Unclosed quoted field', 'Error message should indicate unclosed quote');
  console.log('вң“ Passed');
}

// Test 14: Filter functionality
console.log('Test 14: Filter functionality');
{
  const csv = `name,age,city
John,30,NYC
Jane,25,LA
Bob,35,NYC
Alice,28,Chicago`;

  const result = parseCSV(csv);
  const filtered = result.filter(row => row.age > 25);
  assert(filtered.count() === 3, 'Should have 3 rows with age > 25');
  assert(filtered.rows[0].name === 'John', 'First filtered row should be John');
  assert(filtered.rows[2].name === 'Bob', 'Third filtered row should be Bob');

  const filtered2 = result.filter(row => row.city === 'NYC');
  assert(filtered2.count() === 2, 'Should have 2 rows with city NYC');
  console.log('вң“ Passed');
}

// Test 15: Sum aggregation
console.log('Test 15: Sum aggregation');
{
  const csv = `product,price,quantity
Apple,1.99,10
Banana,0.89,20
Orange,2.49,15`;

  const result = parseCSV(csv);
  const total = result.sum('price');
  assert(total === 5.37, `Total should be 5.37, got ${total}`);

  const totalQty = result.sum('quantity');
  assert(totalQty === 45, 'Total quantity should be 45');
  console.log('вң“ Passed');
}

// Test 16: Average aggregation
console.log('Test 16: Average aggregation');
{
  const csv = `product,price
Apple,2.00
Banana,4.00
Orange,6.00`;

  const result = parseCSV(csv);
  const avg = result.average('price');
  assert(avg === 4, `Average should be 4, got ${avg}`);
  console.log('вң“ Passed');
}

// Test 17: Count aggregation
console.log('Test 17: Count aggregation');
{
  const csv = `name,age
John,30
Jane,25
Bob,35`;

  const result = parseCSV(csv);
  assert(result.count() === 3, 'Should have 3 rows');
  console.log('вң“ Passed');
}

// Test 18: GroupBy aggregation
console.log('Test 18: GroupBy aggregation');
{
  const csv = `name,city,age
John,NYC,30
Jane,LA,25
Bob,NYC,35
Alice,Chicago,28`;

  const result = parseCSV(csv);
  const grouped = result.groupBy('city');
  assert(grouped.has('NYC'), 'Should have NYC group');
  assert(grouped.has('LA'), 'Should have LA group');
  assert(grouped.has('Chicago'), 'Should have Chicago group');

  const nycGroup = grouped.get('NYC');
  assert(nycGroup!.length === 2, 'NYC group should have 2 entries');
  assert(nycGroup![0].name === 'John', 'First NYC entry should be John');
  assert(nycGroup![1].name === 'Bob', 'Second NYC entry should be Bob');

  const laGroup = grouped.get('LA');
  assert(laGroup!.length === 1, 'LA group should have 1 entry');
  console.log('вң“ Passed');
}

// Test 19: Edge case - empty input
console.log('Test 19: Edge case - empty input');
{
