  assert(result.rows[0].string_field === 'trueValue' && typeof result.rows[0].string_field === 'string', 'trueValue should be string');
  assert(result.rows[2].bool_field === 1 && typeof result.rows[2].bool_field === 'number', '1 should be number, not boolean');
  console.log('вң“ Passed');
}

console.log('\nвң“ All tests passed!');

// CSV Parser Library (JavaScript version for testing)

class CSVResult {
  constructor(rows = [], headers = [], errors = []) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  filter(predicate) {
    return new CSVResult(
      this.rows.filter(predicate),
      this.headers,
      this.errors
    );
  }

  sum(column) {
    return this.rows.reduce((acc, row) => {
      const value = row[column];
      const num = typeof value === 'number' ? value : 0;
      return acc + num;
    }, 0);
  }

  average(column) {
    if (this.rows.length === 0) return 0;
    return this.sum(column) / this.rows.length;
  }

  count() {
    return this.rows.length;
  }

  groupBy(column) {
    const groups = new Map();
    for (const row of this.rows) {
      const key = row[column];
      if (!groups.has(key)) {
        groups.set(key, []);
      }
      groups.get(key).push(row);
    }
    return groups;
  }
}

function coerceType(value) {
  if (value === '' || value === null || value === undefined) {
    return null;
  }

  if (value === 'null' || value === 'NULL') {
    return null;
  }

  const lowerValue = value.toLowerCase();
  if (lowerValue === 'true') {
    return true;
  }
  if (lowerValue === 'false') {
    return false;
  }

  if (/^-?\d+$/.test(value)) {
    return parseInt(value, 10);
  }
  if (/^-?\d*\.\d+$/.test(value)) {
    return parseFloat(value);
  }

  return value;
}

function parseFields(line, delimiter, quoteChar) {
  const fields = [];
  let current = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];

    if (char === quoteChar) {
      if (inQuotes && i + 1 < line.length && line[i + 1] === quoteChar) {
        current += quoteChar;
        i += 2;
      } else {
        inQuotes = !inQuotes;
        i++;
      }
    } else if (char === delimiter && !inQuotes) {
      fields.push(current);
      current = '';
      i++;
    } else {
      current += char;
      i++;
    }
  }

  fields.push(current);

  if (inQuotes) {
    return { fields: [], error: 'Unclosed quoted field' };
  }

  return { fields };
}

function parseCSV(input, options = {}) {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  const errors = [];
  const lines = input.split(lineSeparator);

  while (lines.length > 0 && lines[lines.length - 1].trim() === '') {
    lines.pop();
  }

  if (lines.length === 0) {
    return new CSVResult([], [], []);
  }

  const headerFields = parseFields(lines[0], delimiter, quoteChar);
  const headers = headerFields.fields;

  if (headerFields.error) {
    errors.push({ row: 1, message: headerFields.error });
  }

  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    const lineNumber = i + 1;
    const line = lines[i];

    if (line.trim() === '') {
      continue;
    }

    const parsed = parseFields(line, delimiter, quoteChar);

    if (parsed.error) {
      errors.push({ row: lineNumber, message: parsed.error });
      continue;
    }

    const fields = parsed.fields;

    if (fields.length !== headers.length) {
      errors.push({
        row: lineNumber,
        message: `Expected ${headers.length} columns, got ${fields.length}`,
      });
      continue;
    }

    const row = {};
    for (let j = 0; j < headers.length; j++) {
      row[headers[j]] = coerceType(fields[j]);
    }

    rows.push(row);
  }

  return new CSVResult(rows, headers, errors);
}

module.exports = { parseCSV, CSVResult };

// Test runner
const { parseCSV } = require('./csv-parser.js');

function assert(condition, message) {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEqual(actual, expected, message) {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${JSON.stringify(expected)}\nActual: ${JSON.stringify(actual)}`
    );
  }
}

let testCount = 0;
let passCount = 0;

function runTest(name, fn) {
  testCount++;
  try {
    fn();
    passCount++;
    console.log(`вң“ Test ${testCount}: ${name}`);
  } catch (error) {
    console.error(`вң— Test ${testCount}: ${name}`);
    console.error(`  Error: ${error.message}`);
  }
}

// Test 1: Basic parsing
runTest('Basic CSV parsing', () => {
  const csv = `name,age,city
John,30,NYC
Jane,25,LA`;

  const result = parseCSV(csv);
  assert(result.headers.length === 3, 'Should have 3 headers');
  assertEqual(result.headers, ['name', 'age', 'city'], 'Headers should match');
  assert(result.rows.length === 2, 'Should have 2 rows');
  assertEqual(result.rows[0], { name: 'John', age: 30, city: 'NYC' }, 'First row should match');
  assert(result.errors.length === 0, 'Should have no errors');
});

// Test 2: Quoted fields with commas inside
runTest('Quoted fields with commas', () => {
  const csv = `name,address,age
John,"123 Main St, Apt 5",30
Jane,"456 Oak Ave, Suite 100",25`;

  const result = parseCSV(csv);
  assert(result.rows.length === 2, 'Should have 2 rows');
  assertEqual(result.rows[0].address, '123 Main St, Apt 5', 'Should preserve comma inside quotes');
  assertEqual(result.rows[1].address, '456 Oak Ave, Suite 100', 'Should handle multiple quoted fields');
  assert(result.errors.length === 0, 'Should have no errors');
});

// Test 3: Escaped quotes (double quotes)
runTest('Escaped quotes', () => {
  const csv = `name,quote
John,"He said ""Hello"""
Jane,"She replied ""Goodbye"""`;

  const result = parseCSV(csv);
  assert(result.rows.length === 2, 'Should have 2 rows');
  assertEqual(result.rows[0].quote, 'He said "Hello"', 'Should convert "" to single "');
  assertEqual(result.rows[1].quote, 'She replied "Goodbye"', 'Should handle multiple escaped quotes');
  assert(result.errors.length === 0, 'Should have no errors');
});

// Test 4: Custom delimiter
runTest('Custom delimiter', () => {
  const csv = `name|age|city
John|30|NYC
Jane|25|LA`;

  const result = parseCSV(csv, { delimiter: '|' });
  assert(result.headers.length === 3, 'Should have 3 headers');
  assertEqual(result.headers, ['name', 'age', 'city'], 'Headers should match with pipe delimiter');
  assert(result.rows.length === 2, 'Should have 2 rows');
  assertEqual(result.rows[0], { name: 'John', age: 30, city: 'NYC' }, 'Should parse with pipe delimiter');
  assert(result.errors.length === 0, 'Should have no errors');
});

// Test 5: Custom quote character
runTest('Custom quote character', () => {
  const csv = `name,address,age
John,'123 Main St, Apt 5',30
Jane,'456 Oak Ave, Suite 100',25`;

  const result = parseCSV(csv, { quoteChar: "'" });
  assert(result.rows.length === 2, 'Should have 2 rows');
  assertEqual(result.rows[0].address, '123 Main St, Apt 5', 'Should respect custom quote character');
  assert(result.errors.length === 0, 'Should have no errors');
});

// Test 6: Custom line separator
runTest('Custom line separator', () => {
  const csv = `name,age,city\rJohn,30,NYC\rJane,25,LA`;

  const result = parseCSV(csv, { lineSeparator: '\r' });
  assert(result.rows.length === 2, 'Should have 2 rows with custom line separator');
  assertEqual(result.rows[0], { name: 'John', age: 30, city: 'NYC' }, 'Should parse with custom line separator');
  assert(result.errors.length === 0, 'Should have no errors');
});

// Test 7: Type coercion - integers
runTest('Type coercion - integers', () => {
  const csv = `name,age,score
John,30,100
Jane,25,95`;

  const result = parseCSV(csv);
  assert(typeof result.rows[0].age === 'number', 'Age should be a number');
  assert(result.rows[0].age === 30, 'Age should be 30');
  assert(typeof result.rows[0].score === 'number', 'Score should be a number');
  assert(result.rows[0].score === 100, 'Score should be 100');
});

// Test 8: Type coercion - floats
runTest('Type coercion - floats', () => {
  const csv = `name,price,rating
Apple,1.99,4.5
Banana,0.89,4.8`;

  const result = parseCSV(csv);
  assert(typeof result.rows[0].price === 'number', 'Price should be a number');
  assert(result.rows[0].price === 1.99, 'Price should be 1.99');
  assert(result.rows[0].rating === 4.5, 'Rating should be 4.5');
  assert(result.rows[1].rating === 4.8, 'Rating should be 4.8');
});

// Test 9: Type coercion - booleans
runTest('Type coercion - booleans', () => {
  const csv = `name,active,verified
John,true,false
Jane,false,TRUE
Bob,FALSE,true`;

  const result = parseCSV(csv);
  assert(result.rows[0].active === true, 'true should be boolean true');
  assert(result.rows[0].verified === false, 'false should be boolean false');
  assert(result.rows[1].verified === true, 'TRUE should be boolean true (case-insensitive)');
  assert(result.rows[2].active === false, 'FALSE should be boolean false (case-insensitive)');
});

// Test 10: Type coercion - nulls
runTest('Type coercion - nulls', () => {
  const csv = `name,email,phone
John,john@example.com,
Jane,,555-1234
Bob,null,
Alice,bob@example.com,NULL`;

  const result = parseCSV(csv);
  assert(result.rows[0].phone === null, 'Empty string should be null');
  assert(result.rows[1].email === null, 'Empty field should be null');
  assert(result.rows[2].email === null, '"null" should be coerced to null');
  assert(result.rows[3].phone === null, '"NULL" should be coerced to null');
});

// Test 11: Type coercion - strings
runTest('Type coercion - strings', () => {
  const csv = `name,city,notes
John,NYC,Hello world
Jane,LA,Test123
Bob,Chicago,abc-def`;

  const result = parseCSV(csv);
  assert(typeof result.rows[0].city === 'string', 'City should be a string');
  assert(result.rows[0].city === 'NYC', 'City should be "NYC"');
  assert(typeof result.rows[1].notes === 'string', 'Notes should be a string');
  assert(result.rows[1].notes === 'Test123', 'Notes should be "Test123"');
});

// Test 12: Malformed row - wrong column count
runTest('Malformed row - wrong column count', () => {
  const csv = `name,age,city
John,30,NYC
Jane,25
Bob,35,Chicago,Extra`;

  const result = parseCSV(csv);
  assert(result.rows.length === 1, 'Should only have 1 valid row');
  assertEqual(result.rows[0], { name: 'John', age: 30, city: 'NYC' }, 'First row should be valid');
  assert(result.errors.length === 2, 'Should have 2 errors');
  assert(result.errors[0].row === 3, 'First error should be on row 3');
  assert(result.errors[1].row === 4, 'Second error should be on row 4');
});

// Test 13: Malformed row - unclosed quote
runTest('Malformed row - unclosed quote', () => {
  const csv = `name,address,age
John,"123 Main St,30
Jane,"456 Oak Ave",25`;

  const result = parseCSV(csv);
  assert(result.rows.length === 1, 'Should only have 1 valid row');
  assertEqual(result.rows[0], { name: 'Jane', address: '456 Oak Ave', age: 25 }, 'Second row should be valid');
  assert(result.errors.length === 1, 'Should have 1 error');
  assert(result.errors[0].row === 2, 'Error should be on row 2');
  assert(result.errors[0].message === 'Unclosed quoted field', 'Error message should indicate unclosed quote');
});

// Test 14: Filter functionality
runTest('Filter functionality', () => {
  const csv = `name,age,city
John,30,NYC
Jane,25,LA
Bob,35,NYC
Alice,28,Chicago`;

  const result = parseCSV(csv);
  const filtered = result.filter(row => row.age > 25);
  assert(filtered.count() === 3, 'Should have 3 rows with age > 25');
  assert(filtered.rows[0].name === 'John', 'First filtered row should be John');
  assert(filtered.rows[2].name === 'Bob', 'Third filtered row should be Bob');

  const filtered2 = result.filter(row => row.city === 'NYC');
  assert(filtered2.count() === 2, 'Should have 2 rows with city NYC');
});

// Test 15: Sum aggregation
runTest('Sum aggregation', () => {
  const csv = `product,price,quantity
Apple,1.99,10
Banana,0.89,20
Orange,2.49,15`;

  const result = parseCSV(csv);
  const total = result.sum('price');
  assert(total === 5.37, `Total should be 5.37, got ${total}`);

  const totalQty = result.sum('quantity');
  assert(totalQty === 45, 'Total quantity should be 45');
});

// Test 16: Average aggregation
runTest('Average aggregation', () => {
  const csv = `product,price
Apple,2.00
Banana,4.00
Orange,6.00`;

  const result = parseCSV(csv);
  const avg = result.average('price');
  assert(avg === 4, `Average should be 4, got ${avg}`);
});

// Test 17: Count aggregation
runTest('Count aggregation', () => {
  const csv = `name,age
John,30
Jane,25
Bob,35`;

  const result = parseCSV(csv);
  assert(result.count() === 3, 'Should have 3 rows');
});

// Test 18: GroupBy aggregation
runTest('GroupBy aggregation', () => {
  const csv = `name,city,age
John,NYC,30
Jane,LA,25
Bob,NYC,35
Alice,Chicago,28`;

  const result = parseCSV(csv);
  const grouped = result.groupBy('city');
  assert(grouped.has('NYC'), 'Should have NYC group');
  assert(grouped.has('LA'), 'Should have LA group');
  assert(grouped.has('Chicago'), 'Should have Chicago group');

  const nycGroup = grouped.get('NYC');
  assert(nycGroup.length === 2, 'NYC group should have 2 entries');
  assert(nycGroup[0].name === 'John', 'First NYC entry should be John');
  assert(nycGroup[1].name === 'Bob', 'Second NYC entry should be Bob');

  const laGroup = grouped.get('LA');
  assert(laGroup.length === 1, 'LA group should have 1 entry');
});

// Test 19: Edge case - empty input
runTest('Edge case - empty input', () => {
  const csv = '';
  const result = parseCSV(csv);
  assert(result.rows.length === 0, 'Should have 0 rows');
  assert(result.headers.length === 0, 'Should have 0 headers');
  assert(result.errors.length === 0, 'Should have 0 errors');
});

// Test 20: Edge case - single column
runTest('Edge case - single column', () => {
  const csv = `name
John
Jane
Bob`;

  const result = parseCSV(csv);
  assert(result.headers.length === 1, 'Should have 1 header');
  assert(result.headers[0] === 'name', 'Header should be "name"');
  assert(result.rows.length === 3, 'Should have 3 rows');
  assert(result.rows[0].name === 'John', 'First row name should be John');
});

// Test 21: Edge case - single row
runTest('Edge case - single row', () => {
  const csv = `name,age,city
John,30,NYC`;

  const result = parseCSV(csv);
  assert(result.headers.length === 3, 'Should have 3 headers');
  assert(result.rows.length === 1, 'Should have 1 row');
  assertEqual(result.rows[0], { name: 'John', age: 30, city: 'NYC' }, 'Single row should match');
});

// Test 22: Edge case - very large field
runTest('Edge case - very large field', () => {
  const largeText = 'a'.repeat(10000);
  const csv = `name,description,age
John,"${largeText}",30
Jane,"short description",25`;

  const result = parseCSV(csv);
  assert(result.rows.length === 2, 'Should have 2 rows');
  assert(result.rows[0].description.length === 10000, 'Should handle large field');
  assert(result.rows[0].description === largeText, 'Large field should match exactly');
});

// Test 23: Negative numbers
runTest('Negative numbers', () => {
  const csv = `name,balance,change
John,-100.50,+50
Jane,250.75,-25.25`;

  const result = parseCSV(csv);
  assert(result.rows[0].balance === -100.50, 'Negative float should be parsed');
  assert(result.rows[1].change === -25.25, 'Negative float should be parsed');
  assert(typeof result.rows[1].change === 'number', 'Should be number type');
});

// Test 24: Complex quoted field with quotes and commas
runTest('Complex mixing of quotes and delimiters', () => {
  const csv = `name,comment,score
John,"This is a ""great"" product, highly recommend!",95
Jane,"Said ""OK"", then left",80`;

  const result = parseCSV(csv);
  assert(result.rows.length === 2, 'Should have 2 rows');
  assertEqual(result.rows[0].comment, 'This is a "great" product, highly recommend!', 'Should handle complex quoted field');
  assertEqual(result.rows[1].comment, 'Said "OK", then left', 'Should handle complex quoted field with comma');
});

// Test 25: Chained methods
runTest('Chained methods', () => {
  const csv = `name,city,salary
John,NYC,80000
Jane,LA,75000
Bob,NYC,90000
Alice,Chicago,70000`;

  const result = parseCSV(csv);
  const filtered = result.filter(row => row.city === 'NYC');
  const avgSalary = filtered.average('salary');
  assert(avgSalary === 85000, `Average NYC salary should be 85000, got ${avgSalary}`);
});

// Test 26: Empty rows between data
runTest('Empty rows between data', () => {
  const csv = `name,age
John,30

Jane,25`;

  const result = parseCSV(csv);
  assert(result.rows.length === 2, 'Should skip empty row');
  assertEqual(result.rows[0].name, 'John', 'First row should be John');
  assertEqual(result.rows[1].name, 'Jane', 'Second row should be Jane');
});

// Test 27: Multiple custom options together
runTest('Multiple custom options together', () => {
  const csv = `name|address|age
John|'123 Main St, Apt 5'|30
Jane|'456 Oak Ave, Suite 100'|25`;

  const result = parseCSV(csv, { delimiter: '|', quoteChar: "'" });
  assert(result.rows.length === 2, 'Should have 2 rows');
  assertEqual(result.rows[0].address, '123 Main St, Apt 5', 'Should use both custom delimiter and quote char');
  assert(result.errors.length === 0, 'Should have no errors');
});

// Test 28: Numbers vs booleans distinction
runTest('Numbers vs booleans distinction', () => {
  const csv = `name,bool_field,string_field
John,true,trueValue
Jane,false,falseValue
Bob,1,TRUE`;

  const result = parseCSV(csv);
  assert(result.rows[0].bool_field === true && typeof result.rows[0].bool_field === 'boolean', 'true should be boolean');
  assert(result.rows[0].string_field === 'trueValue' && typeof result.rows[0].string_field === 'string', 'trueValue should be string');
  assert(result.rows[2].bool_field === 1 && typeof result.rows[2].bool_field === 'number', '1 should be number, not boolean');
});

console.log(`\nвң“ ${passCount}/${testCount} tests passed`);
if (passCount === testCount) {
  console.log('\nрҹҺү All tests passed!');
  process.exit(0);
} else {
  console.log(`\nвқҢ ${testCount - passCount} test(s) failed`);
  process.exit(1);
}

