// CSV Parser Library
// A robust CSV parser with support for quoted fields, custom delimiters, type coercion, and aggregations

export interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface ParseError {
  row: number;
  message: string;
}

export class CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: ParseError[];

  constructor(
    rows: Record<string, any>[],
    headers: string[],
    errors: ParseError[] = []
  ) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  /**
   * Filter rows based on predicate function
   */
  filter(predicate: (row: Record<string, any>) => boolean): CSVResult {
    return new CSVResult(
      this.rows.filter(predicate),
      this.headers,
      this.errors
    );
  }

  /**
   * Sum numeric values in a column
   */
  sum(column: string): number {
    return this.rows.reduce((acc, row) => {
      const value = row[column];
      const num = typeof value === 'number' ? value : 0;
      return acc + num;
    }, 0);
  }

  /**
   * Calculate average of numeric values in a column
   */
  average(column: string): number {
    if (this.rows.length === 0) return 0;
    return this.sum(column) / this.rows.length;
  }

  /**
   * Count total rows
   */
  count(): number {
    return this.rows.length;
  }

  /**
   * Group rows by column value
   */
  groupBy(column: string): Map<any, Record<string, any>[]> {
    const groups = new Map<any, Record<string, any>[]>();
    for (const row of this.rows) {
      const key = row[column];
      if (!groups.has(key)) {
        groups.set(key, []);
      }
      groups.get(key)!.push(row);
    }
    return groups;
  }
}

/**
 * Detect and coerce a value to its appropriate type
 */
function coerceType(value: string): any {
  // Handle null/empty values
  if (value === '' || value === null || value === undefined) {
    return null;
  }

  if (value === 'null' || value === 'NULL') {
    return null;
  }

  // Handle booleans (case-insensitive)
  const lowerValue = value.toLowerCase();
  if (lowerValue === 'true') {
    return true;
  }
  if (lowerValue === 'false') {
    return false;
  }

  // Handle numbers (int and float)
  if (/^-?\d+$/.test(value)) {
    return parseInt(value, 10);
  }
  if (/^-?\d*\.\d+$/.test(value)) {
    return parseFloat(value);
  }

  // Return as string if no type matched
  return value;
}

/**
 * Parse a CSV string into a CSVResult object with rows and headers
 */
export function parseCSV(
  input: string,
  options: CSVOptions = {}
): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  const errors: ParseError[] = [];
  const lines = input.split(lineSeparator);

  // Filter out empty lines at the end
  while (lines.length > 0 && lines[lines.length - 1].trim() === '') {
    lines.pop();
  }

  if (lines.length === 0) {
    return new CSVResult([], [], []);
  }

  // Parse headers from first line
  const headerFields = parseFields(lines[0], delimiter, quoteChar);
  const headers = headerFields.fields;

  if (headerFields.error) {
    errors.push({ row: 1, message: headerFields.error });
  }

  // Parse data rows
  const rows: Record<string, any>[] = [];
  for (let i = 1; i < lines.length; i++) {
    const lineNumber = i + 1;
    const line = lines[i];

    // Skip empty lines
    if (line.trim() === '') {
      continue;
    }

    const parsed = parseFields(line, delimiter, quoteChar);

    if (parsed.error) {
      errors.push({ row: lineNumber, message: parsed.error });
      continue;
    }

    const fields = parsed.fields;

    // Check if row has same number of columns as headers
    if (fields.length !== headers.length) {
      errors.push({
        row: lineNumber,
        message: `Expected ${headers.length} columns, got ${fields.length}`,
      });
      continue;
    }

    // Create row object with type coercion
    const row: Record<string, any> = {};
    for (let j = 0; j < headers.length; j++) {
      row[headers[j]] = coerceType(fields[j]);
    }

    rows.push(row);
  }

  return new CSVResult(rows, headers, errors);
}

/**
 * Parse a single line into fields, handling quoted values and delimiters
 */
function parseFields(
  line: string,
  delimiter: string,
  quoteChar: string
): { fields: string[]; error?: string } {
  const fields: string[] = [];
  let current = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];

    // Handle quoted section
    if (char === quoteChar) {
      if (inQuotes && i + 1 < line.length && line[i + 1] === quoteChar) {
        // Escaped quote (two quotes in a row = one literal quote)
        current += quoteChar;
        i += 2;
      } else {
        // Toggle quote mode
        inQuotes = !inQuotes;
        i++;
      }
    } else if (char === delimiter && !inQuotes) {
      // Field delimiter (only outside quotes)
      fields.push(current);
      current = '';
      i++;
    } else {
      // Regular character
      current += char;
      i++;
    }
  }

  // Add the last field
  fields.push(current);

  // Check for unclosed quotes
  if (inQuotes) {
    return { fields: [], error: 'Unclosed quoted field' };
  }

  return { fields };
}

