// Test runner
const { parseCSV } = require('./csv-parser.js');

function assert(condition, message) {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEqual(actual, expected, message) {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${JSON.stringify(expected)}\nActual: ${JSON.stringify(actual)}`
    );
  }
}

let testCount = 0;
let passCount = 0;

function runTest(name, fn) {
  testCount++;
  try {
    fn();
    passCount++;
    console.log(`вң“ Test ${testCount}: ${name}`);
  } catch (error) {
    console.error(`вң— Test ${testCount}: ${name}`);
    console.error(`  Error: ${error.message}`);
  }
}

// Test 1: Basic parsing
runTest('Basic CSV parsing', () => {
  const csv = `name,age,city
John,30,NYC
Jane,25,LA`;

  const result = parseCSV(csv);
  assert(result.headers.length === 3, 'Should have 3 headers');
  assertEqual(result.headers, ['name', 'age', 'city'], 'Headers should match');
  assert(result.rows.length === 2, 'Should have 2 rows');
  assertEqual(result.rows[0], { name: 'John', age: 30, city: 'NYC' }, 'First row should match');
  assert(result.errors.length === 0, 'Should have no errors');
});

